// Native 'Webinar: Get All' returns ONE item per webinar.
// Pull webinarKey + organizerKey (so attendees/registrants need no manual key) + subject/date/region.
function regionFromText(t) {
  const s = String(t || '').toLowerCase();
  if (/\b(uk|u\.k\.|united kingdom|england|scotland|wales|ireland|irish|dublin)\b/.test(s)) return 'UKI';
  if (/\b(belgium|benelux|luxembourg|brussels)\b/.test(s)) return 'BeLux';
  if (/\b(netherlands|dutch|holland|amsterdam)\b/.test(s)) return 'NL';
  return null;
}
function regionFromTZ(tz) {
  const s = String(tz || '').toLowerCase();
  if (s.includes('london') || s.includes('dublin')) return 'UKI';
  if (s.includes('brussels') || s.includes('luxembourg')) return 'BeLux';
  if (s.includes('amsterdam')) return 'NL';
  return null;
}
return $input.all().map((it) => {
  const w = it.json;
  const start = (w.times && w.times[0] && w.times[0].startTime) || w.startTime || null;
  const region = regionFromText(w.subject) || regionFromTZ(w.timeZone) || 'UNASSIGNED';
  return { json: {
    event_key: String(w.webinarKey || w.id || ''),
    organizer_key: String(w.organizerKey || ''),
    event_name: w.subject || w.name || null,
    activity_date: start ? String(start).slice(0, 10) : null,
    region_code: region,
    campaign_key: null
  }};
}).filter((i) => i.json.event_key && i.json.activity_date);

// Count registrants per webinar. /registrants returns a bare array which n8n SPLITS into
// one item per registrant — and on split n8n's pairedItem becomes a GLOBAL index, not the
// webinar index, which collapsed every webinar to 1. So we key each registrant to its webinar
// via the webinarKey embedded in joinUrl (/join/<webinarKey>/...), independent of pairedItem.
// Dedup by email (clean string; registrantKey arrives as a precision-damaged number).
const base = $('Flatten Webinars').all();
const byKey = {};
for (const w of base) byKey[w.json.event_key] = new Set();
for (const it of $input.all()) {
  const b = it.json || {};
  const rows = Array.isArray(b) ? b
    : Array.isArray(b.registrants) ? b.registrants
    : (b.registrantKey || b.email || b.joinUrl) ? [b] : [];
  for (const r of rows) {
    const m = String(r.joinUrl || '').match(/\/join\/(\d+)/);
    const ek = m ? m[1] : null;
    const id = r.email || r.registrantKey;
    if (ek && byKey[ek] && id != null) byKey[ek].add(id);
  }
}
return base.map((w) => ({ json: { ...w.json, registrants: byKey[w.json.event_key] ? byKey[w.json.event_key].size : 0 } }));

// Attendee counts from Get Attendees (paginated HAL: _embedded.attendeeParticipationResponses
// + page.totalElements) joined onto the webinar base (carries registrants). count =
// max(totalElements, distinct keys) -> pagination-proof. Then attach SF campaign_key
// (name-date / title+window; dry-runs excluded) and DROP dry-runs from the output.
const base = $('Add Registrants').all();
const acc = base.map(() => ({ keys: new Set(), total: 0 }));
for (const it of $input.all()) {
  let idx = 0;
  const pi = it.pairedItem;
  if (typeof pi === 'number') idx = pi;
  else if (pi && typeof pi.item === 'number') idx = pi.item;
  else if (Array.isArray(pi) && pi[0] && typeof pi[0].item === 'number') idx = pi[0].item;
  const b = it.json || {};
  if (b.page && typeof b.page.totalElements === 'number' && acc[idx]) acc[idx].total = Math.max(acc[idx].total, b.page.totalElements);
  const list = Array.isArray(b) ? b
    : Array.isArray(b.attendees) ? b.attendees
    : (b._embedded && Array.isArray(b._embedded.attendeeParticipationResponses)) ? b._embedded.attendeeParticipationResponses
    : (b._embedded && Array.isArray(b._embedded.attendees)) ? b._embedded.attendees
    : (b.registrantKey || b.attendeeKey || b.email) ? [b] : [];
  for (const a of list) { const k = a.registrantKey || a.attendeeKey || a.email; if (k && acc[idx]) acc[idx].keys.add(k); }
}
const attBy = {};
base.forEach((w, i) => { attBy[w.json.event_key] = Math.max(acc[i].total, acc[i].keys.size); });

// --- SF webinar-campaign matcher (mirrors gotowebinar_sf_match.json) ---
const sf = $('SF: Get Webinar Campaigns').all().map((i) => i.json);
function nameDate(name) { const m = String(name || '').match(/(\d{1,2})[.\/-](\d{1,2})[.\/-](\d{4})/); return m ? `${m[3]}-${m[2].padStart(2, '0')}-${m[1].padStart(2, '0')}` : null; }
function toks(s) { return new Set(String(s || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/\s+/).filter((x) => x.length > 3)); }
function overlap(a, b) { const A = toks(a), B = toks(b); if (!A.size || !B.size) return 0; let n = 0; for (const t of A) if (B.has(t)) n++; return n / Math.min(A.size, B.size); }
const DRY = /\b(dry[\s-]?run|run[\s-]?through|rehearsal|\btest\b)\b/i;
const campaigns = sf.map((c) => ({ campaign_key: c.Id, name: c.Name, name_date: nameDate(c.Name), start: c.StartDate || null, end: c.EndDate || null }));
const usedCampaign = new Set();
function matchCampaign(subject, gtwDate) {
  if (!subject || DRY.test(subject) || !gtwDate) return null;
  let cands = campaigns.filter((c) => c.name_date === gtwDate && !usedCampaign.has(c.campaign_key));
  if (cands.length === 1) return cands[0];
  if (cands.length > 1) return cands.slice().sort((a, b) => overlap(b.name, subject) - overlap(a.name, subject))[0];
  const inWin = campaigns.filter((c) => !usedCampaign.has(c.campaign_key) && c.start && c.end && gtwDate >= c.start && gtwDate <= c.end);
  const ranked = inWin.map((c) => ({ c, score: overlap(c.name, subject) })).sort((a, b) => b.score - a.score);
  return (ranked.length && ranked[0].score >= 0.34) ? ranked[0].c : null;
}

return base.filter((w) => !DRY.test(w.json.event_name || '')).map((w) => {
  const j = w.json;
  const m = matchCampaign(j.event_name, j.activity_date);
  if (m) usedCampaign.add(m.campaign_key);
  return { json: {
    event_key: j.event_key,
    event_name: j.event_name,
    activity_date: j.activity_date,
    region_code: j.region_code,
    campaign_key: m ? m.campaign_key : null,
    registrants: j.registrants,
    attendees: attBy[j.event_key] || 0,
    source: 'gotowebinar'
  }};
});
